import{_ as t,c as i,o as e,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"常见问题: OAuth 认证与模型排查 | Antigravity Auth","description":"了解 Antigravity Auth 插件的常见问题与解决方案。涵盖 OAuth 认证失败排查、模型未找到错误处理、插件兼容性配置等实用指南，帮助你快速定位并解决使用中遇到的各类问题。","frontmatter":{"title":"常见问题: OAuth 认证与模型排查 | Antigravity Auth","sidebarTitle":"认证失败怎么办","subtitle":"常见问题: OAuth 认证与模型排查","description":"了解 Antigravity Auth 插件的常见问题与解决方案。涵盖 OAuth 认证失败排查、模型未找到错误处理、插件兼容性配置等实用指南，帮助你快速定位并解决使用中遇到的各类问题。","order":4},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),o={name:"zh/NoeFabris/opencode-antigravity-auth/faq/index.md"};function r(n,a,d,h,u,s){return e(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>本章节收录了使用 Antigravity Auth 插件时最常遇到的问题和解决方案。无论是 OAuth 认证失败、模型请求报错，还是插件兼容性问题，这里都有对应的排查指南。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确保</p><ul><li>✅ 已完成 <a href="./../start/quick-install/">快速安装</a> 并成功添加账户</li><li>✅ 已完成 <a href="./../start/first-auth-login/">首次认证</a> 并理解 OAuth 流程</li></ul></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>根据你遇到的问题类型，选择对应的排查指南：</p><h3 id="_1-oauth-认证失败排查" tabindex="-1">1. <a href="./common-auth-issues/">OAuth 认证失败排查</a> <a class="header-anchor" href="#_1-oauth-认证失败排查" aria-label="Permalink to &quot;1. [OAuth 认证失败排查](./common-auth-issues/)&quot;">​</a></h3><p>解决 OAuth 认证、令牌刷新和账户相关常见问题。</p><ul><li>浏览器授权成功但终端提示「授权失败」</li><li>突然报错「Permission Denied」或「invalid_grant」</li><li>Safari 浏览器 OAuth 回调失败</li><li>WSL2/Docker 环境下无法完成认证</li></ul><h3 id="_2-迁移账户" tabindex="-1">2. <a href="./migration-guide/">迁移账户</a> <a class="header-anchor" href="#_2-迁移账户" aria-label="Permalink to &quot;2. [迁移账户](./migration-guide/)&quot;">​</a></h3><p>在不同机器间迁移账户，处理版本升级。</p><ul><li>将账户从旧电脑迁移到新电脑</li><li>理解存储格式的版本变化（v1/v2/v3）</li><li>解决迁移后的 invalid_grant 错误</li></ul><h3 id="_3-模型未找到排查" tabindex="-1">3. <a href="./model-not-found/">模型未找到排查</a> <a class="header-anchor" href="#_3-模型未找到排查" aria-label="Permalink to &quot;3. [模型未找到排查](./model-not-found/)&quot;">​</a></h3><p>解决模型未找到、400 错误等模型相关问题。</p><ul><li><code>Model not found</code> 错误排查</li><li><code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code> 400 错误</li><li>MCP 服务器调用报错</li></ul><h3 id="_4-插件兼容性" tabindex="-1">4. <a href="./plugin-compatibility/">插件兼容性</a> <a class="header-anchor" href="#_4-插件兼容性" aria-label="Permalink to &quot;4. [插件兼容性](./plugin-compatibility/)&quot;">​</a></h3><p>解决与 oh-my-opencode、DCP 等插件的兼容性问题。</p><ul><li>正确配置插件加载顺序</li><li>在 oh-my-opencode 中禁用冲突的认证方式</li><li>为并行代理场景启用 PID 偏移</li></ul><h3 id="_5-tos-警告" tabindex="-1">5. <a href="./tos-warning/">ToS 警告</a> <a class="header-anchor" href="#_5-tos-警告" aria-label="Permalink to &quot;5. [ToS 警告](./tos-warning/)&quot;">​</a></h3><p>理解使用风险，避免账户被封禁。</p><ul><li>了解 Google 服务条款限制</li><li>识别高风险场景（新账户、密集请求）</li><li>掌握避免账户封禁的最佳实践</li></ul><h2 id="快速定位问题" tabindex="-1">快速定位问题 <a class="header-anchor" href="#快速定位问题" aria-label="Permalink to &quot;快速定位问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误现象</th><th>推荐阅读</th></tr></thead><tbody><tr><td>认证失败、授权超时</td><td><a href="./common-auth-issues/">OAuth 认证失败排查</a></td></tr><tr><td>invalid_grant、Permission Denied</td><td><a href="./common-auth-issues/">OAuth 认证失败排查</a></td></tr><tr><td>Model not found、400 错误</td><td><a href="./model-not-found/">模型未找到排查</a></td></tr><tr><td>与其他插件冲突</td><td><a href="./plugin-compatibility/">插件兼容性</a></td></tr><tr><td>换新电脑、版本升级</td><td><a href="./migration-guide/">迁移账户</a></td></tr><tr><td>担心账户安全</td><td><a href="./tos-warning/">ToS 警告</a></td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>解决问题后，你可以：</p><ul><li>📖 阅读 <a href="./../advanced/">高级功能</a> 深入掌握多账户、会话恢复等特性</li><li>📚 查阅 <a href="./../appendix/">附录</a> 了解架构设计和完整配置参考</li><li>🔄 关注 <a href="./../changelog/">更新日志</a> 获取最新功能和变更</li></ul>',26)])])}const f=t(o,[["render",r]]);export{p as __pageData,f as default};
